// [snowpack] add styles to the page (skip if no document exists)
if (typeof document !== 'undefined') {
  const code = ".App {\n  background-color: hsl(48, 100%, 97%);\n}\n\n.App-header {\n  height: 4rem;\n  display: flex;\n  flex-direction: column;\n  color: white;\n  grid-area: header;\n}\n\nnav {\n  grid-area: side;\n  /* background-color: hsl(0, 0%, 93%); */\n  padding: 1rem;\n}\n\nnav > div {\n  margin-bottom: 2rem;\n}\n\nmain {\n  grid-area: main;\n  /* background-color: rgb(247, 247, 238); */\n  padding: 1rem;\n  display: flex;\n  justify-content: center;\n}\n\n.content {\n  background-color: white;\n  width: 65ch;\n  box-shadow: 0 0 0 1 black;\n  padding: 1rem;\n}\n\n.content button {\n  font-weight: bold;\n  padding: 4px 8px;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n}\n\n.primary {\n  background-color: black;\n  color: white;\n  border: 1px solid black;\n}\n\n.secondary {\n  background-color: white;\n  color: black;\n  border: 1px solid black;\n}\n\n.App-header h1 {\n  font-size: 2rem;\n  margin: 0;\n}\n.App-header h2 {\n  font-size: 1.25rem;\n  margin: 0;\n}\n\n.cls-3 {\n  fill: #ffe99d;\n}\n\n.yx-prose {\n  /* IM FELL English */\n  font-family: english, sans-serif;\n  font-weight: 400;\n  font-style: normal;\n}\n\n.yx-prose-i {\n  /* IM FELL English Italic */\n  font-family: english, sans-serif;\n  font-weight: 400;\n  font-style: italic;\n}\n\n.yx-heading {\n  /* IM FELL French Canon Regular */\n  font-family: french-canon, serif;\n  font-weight: 400;\n  font-style: normal;\n  text-transform: uppercase;\n  /* IM FELL French Canon SC Regular */\n  /* font-family: french-canon-sc, serif; */\n}\n\n/* .yx-ui-text {\n  font-family: Branding, Futura, 'Avenir Next', Avenir -apple-system,\n    BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell,\n    'Open Sans', 'Helvetica Neue', sans-serif;\n} */\n";

  const styleEl = document.createElement("style");
  const codeEl = document.createTextNode(code);
  styleEl.type = 'text/css';
  styleEl.appendChild(codeEl);
  document.head.appendChild(styleEl);
}